const ONEKOSZYK_API_KEY = "9c4c8b3ee02cdb4eecfc8253f63efb4bec01c8d4edc87513ec3ed96ab3f6fe22c336ad818b000865621655f7bda27d9a0cbc60f0559c0ee25758d4d56b648638";
const ONEKOSZYK_CLIENT_ID = "27e628d8-f4d8-45b2-9dec-94f962ad442d";
// Zmień to na swoją domenę Vercel
const WEBHOOK_URL = "https://frontend-web-omega-ten.vercel.app/api/webhooks/onekoszyk";

async function registerWebhook() {
  try {
    const response = await fetch("https://api.1koszyk.pl/subscriptions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${ONEKOSZYK_API_KEY}`
      },
      body: JSON.stringify({
        url: WEBHOOK_URL,
        events: ["order.paid", "order.created"] // Przykładowe zdarzenia z 1koszyk
      })
    });

    const data = await response.json();
    console.log("Odpowiedź z serwera 1koszyk:");
    console.log(data);
  } catch (err) {
    console.error("Błąd podczas rejestracji webhooka:", err);
  }
}

registerWebhook();

'use client';

import { Suspense, useState } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import { Lock, CreditCard, ChevronLeft, CheckCircle2 } from 'lucide-react';
import Link from 'next/link';

function CheckoutContent() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const plan = searchParams.get('plan') || 'premium_monthly';
  const isLifetime = plan === 'lifetime';
  const isTrial = searchParams.get('trial') === 'true';

  const price = isLifetime ? '199' : (isTrial ? '0' : '29');
  const title = isLifetime ? 'Dostęp Dożywotni' : 'Na Dobranoc Premium';
  const subtitle = isLifetime ? 'Płatność jednorazowa' : (isTrial ? '7-dniowy okres próbny' : 'Abonament miesięczny');

  const startCheckout = async () => {
    try {
      if (isTrial) {
        localStorage.setItem('naDobranoc_trialStart', new Date().toISOString());
        router.push('/dashboard');
        return;
      }

      setError('');
      setIsLoading(true);

      const token = localStorage.getItem('naDobranoc_token');
      const userStr = localStorage.getItem('naDobranoc_user');
      if (!token || !userStr) {
        // Zmuś do logowania
        router.push('/logowanie');
        return;
      }

      const user = JSON.parse(userStr);

      const res = await fetch('http://localhost:3001/v1/checkout/create-session', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({
          planId: plan,
          userId: user.id,
          userEmail: user.email
        })
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Błąd płatności');

      if (data.url) {
        // Przekierowanie do Stripe Checkout (lub mocka)
        window.location.href = data.url;
      }
    } catch (err: any) {
      setError(err.message);
      setIsLoading(false);
    }
  };

  return (
    <div className="w-full max-w-5xl grid lg:grid-cols-[1fr_400px] gap-8 relative z-10">

      {/* Lewa kolumna - Formularz płatności (Stripe-like) */}
      <div>
        <button onClick={() => router.back()} className="inline-flex items-center gap-2 text-slate-400 hover:text-white transition-colors mb-8 group">
          <ChevronLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" /> Anuluj i wróć
        </button>

        <h1 className="text-3xl font-bold mb-8">Dokonaj płatności</h1>

        <div className="space-y-6">

          {/* Przekierowanie do Stripe */}
          <div className="bg-[#111118]/80 backdrop-blur-xl border border-white/10 rounded-2xl p-6">
            <h2 className="text-xl font-bold mb-4">Bezpieczna płatność</h2>
            <p className="text-slate-400 mb-6">Płatności są obsługiwane i w pełni zabezpieczone przez platformę Stripe. Dostępne metody to Karta, BLIK, Google Pay oraz Apple Pay.</p>

            {error && (
              <div className="mb-4 bg-red-500/10 border border-red-500/20 text-red-400 p-3 rounded-xl text-sm text-center">
                {error}
              </div>
            )}

            <div className="flex items-start gap-3 mt-4 mb-6">
              <input type="checkbox" defaultChecked className="mt-1 shrink-0 accent-purple-500" />
              <p className="text-xs text-slate-400">
                {isLifetime 
                  ? 'Wyrażam zgodę na warunki usługi "Na Dobranoc". Jest to jednorazowa płatność gwarantująca dostęp na zawsze bez dodatkowych opłat.' 
                  : isTrial
                  ? 'Rozumiem, że po upływie 7-dniowego okresu próbnego moja subskrypcja odnowi się automatycznie w cenie 29 zł miesięcznie. Z subskrypcji mogę zrezygnować w dowolnym momencie.'
                  : 'Wyrażam zgodę na warunki usługi "Na Dobranoc" i rozumiem, że moja subskrypcja odnowi się automatycznie. Z subskrypcji mogę zrezygnować w dowolnym momencie.'}
              </p>
            </div>

            <button 
              onClick={startCheckout} 
              disabled={isLoading}
              className="w-full flex items-center justify-center gap-2 py-4 bg-gradient-to-r from-purple-600 to-pink-600 text-white font-bold rounded-xl hover:scale-[1.02] transition-transform shadow-[0_0_20px_rgba(168,85,247,0.3)] disabled:opacity-70 disabled:hover:scale-100"
            >
              <Lock className="w-4 h-4" /> 
              {isLoading ? 'Przekierowywanie do bramki...' : (isTrial ? 'Rozpocznij darmowy okres próbny' : `Zapłać ${price} zł i zyskaj dostęp`)}
            </button>
          </div>
        </div>
      </div>

      {/* Prawa kolumna - Podsumowanie zamówienia */}
      <div className="lg:sticky lg:top-12 h-fit">
        <div className="bg-gradient-to-b from-[#111118] to-[#0a0a0e] border border-white/10 rounded-3xl p-8 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-purple-500/20 blur-[50px] pointer-events-none" />

          <h3 className="text-lg font-bold mb-6">Podsumowanie {isLifetime ? 'zamówienia' : 'subskrypcji'}</h3>

          <div className="flex items-center gap-4 mb-6 pb-6 border-b border-white/10">
            <div className="w-16 h-16 rounded-2xl bg-purple-500/10 flex items-center justify-center border border-purple-500/20 shrink-0">
              <span className="text-2xl">🌙</span>
            </div>
            <div>
              <h4 className="font-bold text-white leading-tight">{title}</h4>
              <p className="text-sm text-slate-400">{subtitle}</p>
            </div>
            <div className="ml-auto font-bold text-right shrink-0 pl-2">
              {price} zł
            </div>
          </div>

          <ul className="space-y-4 mb-8">
            {['Dostęp do biblioteki bajek', 'Tryb samolotowy (Offline)', 'Możliwość podpięcia 3 urządzeń', 'Panel kontroli rodzica', 'Brak reklam i powiadomień'].map((item, idx) => (
              <li key={idx} className="flex items-center gap-3 text-sm text-slate-300">
                <CheckCircle2 className="w-4 h-4 text-emerald-400 shrink-0" /> {item}
              </li>
            ))}
          </ul>

          <div className="flex items-center justify-between font-bold text-xl pt-6 border-t border-white/10">
            <span>Do zapłaty dzisiaj</span>
            <span>{price} zł</span>
          </div>
          {isTrial && (
            <div className="flex items-center justify-between font-medium text-sm pt-2 text-slate-400">
              <span>Po 7 dniach</span>
              <span>29 zł / miesiąc</span>
            </div>
          )}
          <p className="text-xs text-slate-500 text-right mt-2">W tym 23% VAT</p>
        </div>
      </div>

    </div>
  );
}

export default function CheckoutPage() {
  return (
    <div className="min-h-screen bg-[#0a0a0e] text-white flex justify-center py-12 px-4 selection:bg-purple-500/30">

      {/* Premium Blurs */}
      <div className="fixed top-[-20%] left-[-10%] w-[60%] h-[800px] bg-purple-900/10 blur-[150px] rounded-full pointer-events-none z-0" />
      <div className="fixed bottom-[-20%] right-[-10%] w-[50%] h-[800px] bg-pink-900/10 blur-[150px] rounded-full pointer-events-none z-0" />

      <Suspense fallback={<div className="relative z-10 py-20 text-slate-400">Ładowanie koszyka...</div>}>
        <CheckoutContent />
      </Suspense>

    </div>
  );
}

