'use client';

import { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { LogOut, Smartphone, Tablet, Plus, Settings, CreditCard, ChevronRight, Lock, Download, ArrowLeft, Bell } from 'lucide-react';
import Link from 'next/link';
import { useRouter, useSearchParams } from 'next/navigation';
import { Suspense } from 'react';

export default function DashboardPage() {
  return (
    <Suspense fallback={<div className="min-h-screen bg-[#0a0a0e] text-white flex items-center justify-center">Ładowanie...</div>}>
      <DashboardContent />
    </Suspense>
  );
}

function DashboardContent() {
  const [trialState, setTrialState] = useState<'none' | 'active' | 'expired'>('none');
  const [trialDaysLeft, setTrialDaysLeft] = useState<number>(0);
  const [isClient, setIsClient] = useState(false);
  const [activeTab, setActiveTab] = useState<'devices' | 'download' | 'subscription' | 'settings'>('devices');
  const [userName, setUserName] = useState('Rodzicu');
  const [devices, setDevices] = useState<unknown[]>([]);
  const [maxDevices, setMaxDevices] = useState(3);
  const [license, setLicense] = useState<unknown>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [showNotifications, setShowNotifications] = useState(false);
  const router = useRouter();
  const searchParams = useSearchParams();

  useEffect(() => {
    setIsClient(true);

    const fetchProfile = async () => {
      try {
        const { supabase } = await import('@/lib/supabase');
        const { data: { session }, error: sessionError } = await supabase.auth.getSession();

        if (sessionError || !session) {
          setIsLoading(false);
          router.push('/logowanie');
          return;
        }

        const user = session.user;
        setUserName(user.user_metadata?.name || user.email?.split('@')[0] || 'Rodzicu');

        // Pobierz profil usera by sprawdzić is_premium
        const { data: profile, error: profileError } = await supabase
          .from('profiles')
          .select('*')
          .eq('id', user.id)
          .single();

        if (profileError && profileError.code !== 'PGRST116') {
          console.error('Błąd pobierania profilu:', profileError);
        }

        if (profile && profile.is_premium) {
          setTrialState('none');
          setLicense({ plan: 'lifetime', maxDevices: 5 });
          setMaxDevices(5);
        } else {
          setTrialState('expired');
          setLicense({ plan: 'free', maxDevices: 1 });
          setMaxDevices(1);
        }

        // Fake devices for now
        setDevices([
          { deviceId: 'dev_1', name: 'Telefon', type: 'smartphone', active: true, lastActive: new Date().toISOString() }
        ]);

      } catch (err) {
        console.error('Ogólny błąd ładowania dashboardu:', err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchProfile();
  }, [searchParams, router]);

  const removeDevice = async (deviceId: string) => {
    if (!confirm('Czy na pewno chcesz usunąć to urządzenie?')) return;

    const token = localStorage.getItem('naDobranoc_token');
    if (!token) return;

    try {
      const res = await fetch(`http://localhost:3001/v1/licenses/devices/${deviceId}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` }
      });
      const data = await res.json();
      if (res.ok) {
        setDevices(data.devices || []);
      } else {
        alert(data.error || 'Błąd usuwania urządzenia');
      }
    } catch (err) {
      console.error(err);
      alert('Błąd sieci');
    }
  };

  const getPaddedDevices = () => {
    const padded = [...devices];
    while (padded.length < maxDevices) {
      padded.push({ deviceId: 'empty_' + padded.length, type: 'empty', active: false });
    }
    return padded;
  };

  if (!isClient || isLoading) {
    return <div className="min-h-screen bg-[#0a0a0e] flex items-center justify-center text-slate-400">Ładowanie profilu...</div>;
  }

  if (!isClient) {
    return <div className="min-h-screen bg-[#0a0a0e]" />; // Zapobieganie błędom hydracji
  }

  // BLOKADA DOSTĘPU PO 7 DNIACH
  if (trialState === 'expired') {
    return (
      <div className="min-h-screen bg-[#0a0a0e] text-white flex flex-col items-center justify-center p-6 selection:bg-red-500/30 relative">
        <button onClick={() => router.back()} className="absolute top-8 left-8 md:top-12 md:left-12 inline-flex items-center gap-2 text-slate-400 hover:text-white transition-colors group z-20 font-medium">
          <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" /> Powrót
        </button>

        <div className="max-w-md w-full bg-[#111118] border border-red-500/30 rounded-3xl p-8 text-center shadow-[0_0_50px_rgba(239,68,68,0.1)] relative overflow-hidden">
          <div className="absolute top-0 left-1/2 -translate-x-1/2 w-48 h-48 bg-red-500/20 blur-[60px] pointer-events-none" />

          <div className="w-20 h-20 rounded-full bg-red-500/10 border border-red-500/20 flex items-center justify-center mx-auto mb-6 relative z-10">
            <Lock className="w-10 h-10 text-red-400" />
          </div>

          <h2 className="text-2xl font-bold mb-4 relative z-10 text-white">Brak Aktywnej Licencji</h2>
          <p className="text-slate-400 mb-8 relative z-10 leading-relaxed text-sm">
            Dostęp do biblioteki bajek, trybu offline i funkcji Premium jest zablokowany. Aby odblokować wszystkie możliwości aplikacji na zawsze i zapewnić dziecku spokojny sen każdego wieczoru, wybierz dostęp dożywotni.
          </p>

          <Link href="/checkout" className="w-full flex items-center justify-center gap-2 py-4 bg-gradient-to-r from-red-600 to-pink-600 text-white font-bold rounded-xl hover:scale-[1.02] transition-transform relative z-10">
            Odblokuj Dostęp Dożywotni
          </Link>
          <button 
            onClick={() => {
              localStorage.removeItem('naDobranoc_trialStart');
              window.location.reload();
            }} 
            className="mt-4 text-xs text-slate-600 hover:text-slate-400 underline relative z-10"
          >
            [Dev/Test] Resetuj trial
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0a0a0e] text-white selection:bg-purple-500/30">
      <nav className="border-b border-white/5 bg-[#0a0a0e]/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => router.back()} className="flex items-center gap-2 text-slate-400 hover:text-white transition-colors group">
              <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
              <span className="hidden sm:inline">Powrót</span>
            </button>
            <div className="h-6 w-px bg-white/10 hidden sm:block"></div>
            <Link href="/" className="text-2xl font-serif italic text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-pink-400 font-bold">
              Na Dobranoc
            </Link>
          </div>
          <div className="flex items-center gap-6">
            <span className="text-sm font-medium text-slate-400">Witaj, {userName}</span>
            <div className="relative">
              <button onClick={() => setShowNotifications(!showNotifications)} className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center hover:bg-white/10 transition-colors relative" title="Powiadomienia">
                <Bell className="w-5 h-5 text-slate-300" />
                <span className="absolute top-2 right-2 w-2 h-2 rounded-full bg-pink-500"></span>
              </button>

              <AnimatePresence>
                {showNotifications && (
                  <motion.div 
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: 10 }}
                    className="absolute right-0 top-14 w-80 bg-[#111118] border border-white/10 rounded-2xl p-4 shadow-2xl z-50"
                  >
                    <h3 className="font-bold text-white mb-4">Powiadomienia</h3>
                    <div className="space-y-3">
                      <div className="p-3 bg-white/5 rounded-xl border border-white/5">
                        <p className="text-sm font-medium text-white mb-1">Dostępna nowa wersja 1.0.4!</p>
                        <p className="text-xs text-slate-400">Pobierz najnowszą paczkę APK z poprawkami wydajności.</p>
                      </div>
                      <div className="p-3 bg-white/5 rounded-xl border border-white/5">
                        <p className="text-sm font-medium text-white mb-1">Subskrypcja aktywna</p>
                        <p className="text-xs text-slate-400">Dziękujemy za wybranie pakietu Premium.</p>
                      </div>
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>
            </div>
            <button 
              onClick={async () => {
                const { supabase } = await import('@/lib/supabase');
                await supabase.auth.signOut();
                localStorage.removeItem('naDobranoc_user');
