// Komponent renderujący migoczące i spadające gwiazdy po prawej stronie tła
function StarrySky() {
  return (
    <div className="absolute top-0 right-0 w-full lg:w-[55%] h-full pointer-events-none overflow-hidden z-0">
      {/* Migoczące gwiazdy */}
      {[...Array(150)].map((_, i) => {
        const top = (i * 17) % 100;
        const left = (i * 29) % 100;
        const isBlinking = i % 2 === 0;
        return (
          <div
            key={`star-${i}`}
            className={`absolute bg-white rounded-full ${isBlinking ? 'animate-pulse' : 'opacity-40'}`}
            style={{ 
              top: `${top}%`, 
              left: `${left}%`,
              width: i % 3 === 0 ? '3px' : '2px',
              height: i % 3 === 0 ? '3px' : '2px',
              animationDuration: `${2 + (i % 4)}s`,
              animationDelay: `${(i * 0.3) % 2}s`
            }}
          />
        );
      })}

      {/* Rzadkie komety (punkciki z długą poświatą w formie ogona) */}
      {[...Array(3)].map((_, i) => {
        // Konfiguracja dla każdej z 3 komet, żeby pojawiała się jedna dokładnie co 10 sekund
        const config = [
          { top: 10, left: 80, angle: 145, delay: 5 },   // Leci po 5s
          { top: 20, left: 10, angle: 35, delay: 15 },   // Leci po 15s
          { top: -5, left: 60, angle: 105, delay: 25 }   // Leci po 25s
        ][i];

        return (
          <div 
            key={`comet-${i}`}
            className="absolute"
            style={{ 
              top: `${config.top}%`, 
              left: `${config.left}%`, 
              transform: `rotate(${config.angle}deg)` 
            }}
          >
            <motion.div
              className="relative flex items-center"
              style={{ width: '120px', height: '2px' }}
              initial={{ x: '-200px', opacity: 0 }}
              animate={{ x: '1500px', opacity: [0, 1, 1, 0] }}
              transition={{ 
                duration: 4, 
                repeat: Infinity, 
                delay: config.delay, 
                repeatDelay: 26, // 4s ruchu + 26s pauzy = powtarza się co 30s. Mając 3 komety mamy zjawisko co równe 10s!
                ease: "linear" 
              }}
            >
              {/* Ogon komety (rozmyta poświata) */}
              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-purple-300/40 to-white/90 rounded-full blur-[1px]" />
              {/* Główka komety (Świecący punkt na przodzie ruchu) */}
              <div className="absolute right-0 w-[4px] h-[4px] bg-white rounded-full shadow-[0_0_12px_rgba(255,255,255,1),_0_0_20px_rgba(236,72,153,0.8)]" />
            </motion.div>
          </div>
        );
      })}
    </div>
  );
}

function PhoneMockup({ src, alt, glowColor, className = "w-[280px] h-[580px]", priority = true, shadowOpacity = 0 }: { src: string, alt: string, glowColor: string, className?: string, priority?: boolean, shadowOpacity?: number }) {
  const depth = 25;
  return (
    <div className={`relative ${className}`} style={{ transformStyle: 'preserve-3d' }}>

      {/* 1. TYŁ I GRUBOŚĆ (Boczne płytki tworzące efekt 3D) */}
      {[...Array(depth)].map((_, i) => (
        <div 
          key={i}
          className={`absolute inset-0 rounded-[2.5rem] md:rounded-[3rem] bg-[#1a1a24] ${i === depth - 1 ? 'border border-[#2a2a3b]' : ''}`}
          style={{ 
            transform: `translateZ(-${i + 1}px)`,
            boxShadow: i === depth - 1 ? `0 20px 60px ${glowColor}` : 'none'
          }}
        />
      ))}

      {/* Przyciemnienie plecków dla telefonów odwróconych tyłem do ekranu */}
      <motion.div 
        className="absolute inset-0 rounded-[2.5rem] md:rounded-[3rem] bg-[#050508] pointer-events-none"
        style={{ transform: `translateZ(-${depth + 0.5}px)` }}
        animate={{ opacity: shadowOpacity }}
        transition={{ duration: 0.5 }}
      />

      {/* 2. PLANSZA ZE ZRZUTEM EKRANU (Zabezpieczona przed przenikaniem) */}
      <div 
        className="absolute inset-0 rounded-[2.5rem] md:rounded-[3rem] border-[6px] md:border-[8px] border-[#1a1a24] bg-[#0a0a0e]"
        style={{ transform: 'translateZ(1px)', backfaceVisibility: 'hidden' }}
      >
        {/* Idealne docięcie zawartości (clip-path omija błąd overflow-hidden w WebKit 3D) */}
        <div className="absolute inset-0 w-full h-full [clip-path:inset(0_round_2rem)] md:[clip-path:inset(0_round_2.5rem)]">
          <Image src={src} alt={alt} fill className="object-cover" priority={priority} />

          {/* Notch - wcięcie */}
          <div className="absolute top-0 inset-x-0 h-5 md:h-6 flex justify-center z-20">
            <div className="w-24 md:w-28 h-4 md:h-5 bg-[#1a1a24] rounded-b-xl md:rounded-b-2xl" />
          </div>

          {/* Poświata odblaskowa */}
          <div className="absolute inset-0 bg-gradient-to-tr from-transparent via-white/10 to-transparent pointer-events-none z-10" />

          {/* Maska przyciemniająca dla elementów z tyłu karuzeli */}
          <motion.div 
            className="absolute inset-0 bg-[#050508] pointer-events-none z-30"
            animate={{ opacity: shadowOpacity }}
            transition={{ duration: 0.5 }}
          />
        </div>
      </div>
    </div>
  );
}

