// Komponent z w pełni trójwymiarową karuzelą 3D (Cylinder)
function ScreenshotsSection() {
  const [activeIndex, setActiveIndex] = useState(0);

  const screens = [
    '/screenshots/Screenshot_20260523_223956_sklep.png',
    '/screenshots/Screenshot_20260523_224011_sklep.png',
    '/screenshots/Screenshot_20260523_224041_sklep.png',
    '/screenshots/Screenshot_20260523_224130_sklep.png',
    '/screenshots/Screenshot_20260523_224147_sklep.png',
    '/screenshots/Screenshot_20260523_224219_sklep.png',
    '/screenshots/Screenshot_20260523_224327_sklep.png',
    '/screenshots/Screenshot_20260523_224340_sklep.png',
    '/screenshots/Screenshot_20260523_224357_sklep.png',
    '/screenshots/Screenshot_20260523_224415_sklep.png',
    '/screenshots/Screenshot_20260523_224424_sklep.png',
  ];

  const totalItems = screens.length;
  const angleStep = 360 / totalItems;
  const radius = 650;
  const zoomOffset = 200;

  const rotateCarousel = (direction: 'left' | 'right') => {
    setActiveIndex((prev) => direction === 'left' ? prev - 1 : prev + 1);
  };

  return (
    <section className="relative z-30 bg-[#050508] border-y border-white/5 mt-12 shadow-[inset_0_0_100px_rgba(0,0,0,1)]">
      <div className="absolute top-0 inset-x-0 h-px bg-gradient-to-r from-transparent via-purple-500/50 to-transparent" />

      {/* Dodatkowy kontener z overflow-hidden, ale ODDZIELONY od perspektywy 3D */}
      <div className="w-full overflow-hidden py-24 md:py-32">
        <div className="text-center mb-16 px-6 relative z-10">
          <h2 className="text-3xl md:text-5xl font-bold text-white mb-6">
            Aplikacja, która szepcze <span className="font-serif italic text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-pink-400">dobranoc</span>
          </h2>
          <p className="text-lg text-slate-400 font-light max-w-2xl mx-auto">
            Aksamitny interfejs pozbawiony agresywnych bodźców. Zero rażącego światła – tylko czysty relaks i przygotowanie do snu.
          </p>
        </div>

        {/* Kontener perspektywy 3D */}
        <div className="relative max-w-[1400px] mx-auto h-[550px] md:h-[650px] flex items-center justify-center perspective-[1500px]">

          <button 
            onClick={() => rotateCarousel('left')}
            className="absolute left-4 sm:left-12 z-40 w-14 h-14 rounded-full bg-[#1a1a24]/80 border border-white/10 text-white flex items-center justify-center backdrop-blur-md transition-all duration-300 hover:bg-purple-600 hover:scale-110 shadow-[0_0_20px_rgba(168,85,247,0.3)]"
          >
            <ChevronLeft className="w-7 h-7 -ml-1" />
          </button>

          {/* Główny kontener karuzeli preserve-3d */}
          <motion.div 
            className="relative w-[240px] md:w-[280px] h-[500px] md:h-[580px]"
            animate={{ 
              rotateY: -activeIndex * angleStep, 
              z: -radius + zoomOffset 
            }}
            transition={{ type: "spring", stiffness: 50, damping: 14 }}
            style={{ transformStyle: 'preserve-3d' }}
          >
            {screens.map((src, i) => {
              const angle = i * angleStep;

              const normalizedActive = ((activeIndex % totalItems) + totalItems) % totalItems;
              let dist = Math.abs(i - normalizedActive);
              if (dist > totalItems / 2) dist = totalItems - dist;

              const shadowOverlay = dist === 0 ? 0 : dist === 1 ? 0.6 : 0.9;

              return (
                <div
                  key={`3d-screen-${i}`}
                  className="absolute inset-0 flex items-center justify-center"
                  style={{
                    transform: `rotateY(${angle}deg) translateZ(${radius}px)`,
                    transformStyle: 'preserve-3d', 
                  }}
                >
                  {/* Poświata aktywnego telefonu */}
                  <motion.div 
                    className="absolute inset-[-14px] bg-gradient-to-r from-purple-500 to-pink-500 rounded-[3.6rem] blur-[24px]"
                    animate={{ opacity: dist === 0 ? 0.8 : 0 }}
                    transition={{ duration: 0.4 }}
                    style={{ transform: 'translateZ(-30px)' }}
                  />

                  <PhoneMockup 
                    src={src} 
                    alt={`Zrzut ekranu ${i+1}`} 
                    glowColor="rgba(0,0,0,0)"
                    className="w-full h-full" 
                    priority={false}
                    shadowOpacity={shadowOverlay}
                  />
                </div>
              );
            })}
          </motion.div>

          <button 
            onClick={() => rotateCarousel('right')}
            className="absolute right-4 sm:right-12 z-40 w-14 h-14 rounded-full bg-[#1a1a24]/80 border border-white/10 text-white flex items-center justify-center backdrop-blur-md transition-all duration-300 hover:bg-purple-600 hover:scale-110 shadow-[0_0_20px_rgba(168,85,247,0.3)]"
          >
            <ChevronRight className="w-7 h-7 ml-1" />
          </button>
        </div>
      </div>
    </section>
  );
}

