function DemoModal({ onClose }: { onClose: () => void }) {
  const demos = [
    { id: 1, title: 'Dobranoc mały traktorze', duration: '0:30', color: 'from-emerald-500 to-green-500', url: 'https://pub-8791828a7ff445cb857b07c14f225bd7.r2.dev/storys/Kr%C3%B3tkie/Dobranoc%20ma%C5%82y%20traktorze/dobranoc%20ma%C5%82y%20traktorze.m4a' },
    { id: 2, title: 'Festiwal latających wysp', duration: '0:30', color: 'from-blue-500 to-indigo-500', url: 'https://pub-8791828a7ff445cb857b07c14f225bd7.r2.dev/storys/Spokojne/Festival%20lataj%C4%85cych%20wysp/FESTIWAL%20LATAJ%C4%84CYCH%20WYSP.m4a' },
    { id: 3, title: 'Ekspedycja na Wyspę...', duration: '0:30', color: 'from-purple-500 to-pink-500', url: 'https://pub-8791828a7ff445cb857b07c14f225bd7.r2.dev/storys/Przygodowe/Ekspedycja%20na%20Wysp%C4%99%20Cyfrowego%20Zegarmistrza/Ekspedycja%20na%20Wysp%C4%99%20Cyfrowego%20Zegarmistrza.m4a' },
  ];

  const [playingId, setPlayingId] = useState<number | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (playingId && audioRef.current) {
      interval = setInterval(() => {
        if (audioRef.current && audioRef.current.currentTime >= 30) {
          audioRef.current.pause();
          setPlayingId(null);
        }
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [playingId]);

  const togglePlay = (id: number, url: string) => {
    if (playingId === id) {
      audioRef.current?.pause();
      setPlayingId(null);
    } else {
      if (audioRef.current) {
        audioRef.current.src = url;
        audioRef.current.play().catch(() => console.log('Błąd odtwarzania audio'));
      }
      setPlayingId(id);
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[100] flex items-center justify-center p-4 md:p-6"
    >
      <div className="absolute inset-0 bg-[#0a0a0e]/90 backdrop-blur-md" onClick={onClose} />
      <motion.div 
        initial={{ scale: 0.95, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.95, y: 20 }}
        className="relative w-full max-w-lg bg-[#111118] border border-white/10 rounded-3xl p-6 md:p-8 shadow-2xl overflow-hidden"
      >
        <div className="absolute top-0 right-0 w-[200px] h-[200px] bg-purple-500/10 blur-[60px] pointer-events-none" />

        <div className="flex justify-between items-center mb-8 relative z-10">
          <div>
            <h3 className="text-2xl font-bold text-white mb-1">Posłuchaj Próbek</h3>
            <p className="text-slate-400 text-sm">Zanurz się w świecie &quot;Na Dobranoc&quot;</p>
          </div>
          <button onClick={onClose} className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center hover:bg-white/10 transition-colors">
            <X className="w-5 h-5 text-white" />
          </button>
        </div>

        <div className="space-y-4 relative z-10">
          {demos.map(demo => (
            <div key={demo.id} className="flex items-center gap-4 p-4 rounded-2xl bg-white/5 hover:bg-white/10 border border-white/5 transition-colors">
              <button 
                onClick={() => togglePlay(demo.id, demo.url)}
                className={`w-12 h-12 rounded-full bg-gradient-to-br ${demo.color} flex items-center justify-center shadow-lg hover:scale-105 transition-transform shrink-0`}
              >
                {playingId === demo.id ? <Pause className="w-5 h-5 text-white" fill="currentColor" /> : <PlayCircle className="w-5 h-5 text-white" />}
              </button>
              <div className="flex-1">
                <h4 className="font-bold text-white text-base leading-tight mb-1">{demo.title}</h4>
                <p className="text-xs text-slate-400 font-medium tracking-wide">{demo.duration}</p>
              </div>
              {playingId === demo.id && (
                <div className="flex gap-1 items-end h-5">
                  <span className="w-1.5 bg-purple-400 h-full animate-[bounce_1s_infinite]" />
                  <span className="w-1.5 bg-pink-400 h-3 animate-[bounce_1.2s_infinite]" />
                  <span className="w-1.5 bg-blue-400 h-4 animate-[bounce_0.8s_infinite]" />
                </div>
              )}
            </div>
          ))}
        </div>

        <audio ref={audioRef} onEnded={() => setPlayingId(null)} />
      </motion.div>
    </motion.div>
  );
}

